    brief: topic.brief,
    pubDate: pubDate,
    readTime: '6 min read'
  }
}];

const response = $input.first().json;
const topicData = $('Prepare Topic Data').first().json;

// Extract text from Claude response
const contentBlock = response.content.find(b => b.type === 'text');
if (!contentBlock) throw new Error('No text block in Claude response');

let raw = contentBlock.text.trim();
// Strip any accidental markdown fences
raw = raw.replace(/^```json\s*/,'').replace(/^```\s*/,'').replace(/\s*```$/,'').trim();

let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  throw new Error('Failed to parse Claude JSON: ' + e.message + ' | Raw: ' + raw.substring(0,200));
}

return [{
  json: {
    ...topicData,
    meta_description: parsed.meta_description,
    body_html: parsed.body_html,
    card_description: parsed.card_description,
    read_time: parsed.read_time || '6 min read'
  }
}];

