const sha = response.sha;
const blogHtml = Buffer.from(response.content, 'base64').toString('utf8');

// Build the new blog card HTML
const newCard = `<a href="/blog/${articleData.slug}.html" class="blog-card">
  <div class="blog-card-img" style="background:${articleData.hero_gradient};"><span>${articleData.hero_emoji}</span></div>
  <div class="blog-card-body">
    <div class="blog-tag">${articleData.tag}</div>
    <h3>${articleData.title}</h3>
    <p>${articleData.card_description}</p>
    <div class="blog-meta"><span>${articleData.read_time}</span><span>·</span><span>${articleData.pubDate}</span></div>
  </div>
</a>`;

// Insert new card right after the blog-grid opening tag
const insertMarker = '<div class="blog-grid">';
if (!blogHtml.includes(insertMarker)) {
  throw new Error('Could not find blog-grid insertion point in blog.html');
}

const updatedHtml = blogHtml.replace(
  insertMarker,
  insertMarker + '\n' + newCard
);

// Verify single style block
const styleCount = (updatedHtml.match(/<style>/g) || []).length;
if (styleCount !== 1) throw new Error('Style block count is ' + styleCount + ', expected 1');

const encoded = Buffer.from(updatedHtml).toString('base64');

return [{ json: { sha, encoded_content: encoded, title: articleData.title } }];

